import requests
import urllib.parse
import ipaddress
import re
from typing import Optional

def fetch_url_content(url: str, allowed_domains: Optional[list] = None, max_redirects: int = 3) -> str:
    """
    Fetch and display content from a URL with security protections.
    
    Args:
        url (str): The URL to fetch content from
        allowed_domains (list): List of allowed domains (optional)
        max_redirects (int): Maximum number of redirects allowed
    
    Returns:
        str: Content from the URL
        
    Raises:
        ValueError: If URL is invalid or blocked
        requests.RequestException: If request fails
    """
    
    # Validate URL format
    if not url or not isinstance(url, str):
        raise ValueError("Invalid URL provided")
    
    try:
        parsed_url = urllib.parse.urlparse(url)
        if not parsed_url.scheme or not parsed_url.netloc:
            raise ValueError("Invalid URL format")
        
        # Check for allowed domains if specified
        if allowed_domains:
            if parsed_url.netloc not in allowed_domains:
                raise ValueError(f"Domain {parsed_url.netloc} not in allowed list")
        
        # Validate and block internal IP ranges
        try:
            ip = ipaddress.ip_address(parsed_url.netloc)
            if ip.is_loopback or ip.is_private or ip.is_reserved:
                raise ValueError("Access to internal network addresses is blocked")
        except ValueError:
            # Not an IP address, check if it's a valid hostname
            if not re.match(r'^[a-zA-Z0-9.-]+$', parsed_url.netloc):
                raise ValueError("Invalid hostname format")
        
        # Set up request with security headers
        headers = {
            'User-Agent': 'Partner-Integration-Client/1.0',
            'Accept': '*/*',
            'Accept-Encoding': 'gzip, deflate',
            'Connection': 'close'
        }
        
        # Make request with redirect limits
        response = requests.get(
            url,
            headers=headers,
            timeout=10,
            allow_redirects=True,
            max_redirects=max_redirects
        )
        
        # Check for successful response
        response.raise_for_status()
        
        return response.text
        
    except requests.exceptions.RequestException as e:
        raise ValueError(f"Failed to fetch URL: {str(e)}")

# Example usage for webhook processing
def process_webhook_request(url: str, allowed_domains: list) -> str:
    """
    Process webhook request with security validation.
    
    Args:
        url (str): Webhook URL
        allowed_domains (list): List of allowed domains for webhook endpoints
        
    Returns:
        str: Response content
    """
    return fetch_url_content(url, allowed_domains)